=<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Content Review — FM Matrix</title>
  <link href="https://fonts.googleapis.com/css2?family=DM+Sans:ital,wght@0,300;0,400;0,500;0,600;1,400&family=DM+Mono:wght@400;500&display=swap" rel="stylesheet"/>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --bg:        #F5F4F0;
      --surface:   #FFFFFF;
      --surface2:  #F9F8F5;
      --border:    rgba(0,0,0,0.08);
      --border-md: rgba(0,0,0,0.14);
      --text-1:    #1A1916;
      --text-2:    #5C5A54;
      --text-3:    #9B9890;
      --green-bg:  #E4F5EC;
      --green-bd:  #34A85A;
      --green-tx:  #1A5E34;
      --red-bg:    #FDECEA;
      --red-bd:    #E04040;
      --red-tx:    #7A1A1A;
      --blue-bg:   #EAF1FD;
      --blue-bd:   #3A7BDB;
      --blue-tx:   #1B3D7A;
      --amber-bg:  #FEF5E4;
      --amber-bd:  #D4900E;
      --amber-tx:  #6B4500;
      --radius-sm: 6px;
      --radius-md: 10px;
      --radius-lg: 16px;
    }

    body {
      font-family: 'DM Sans', sans-serif;
      background: var(--bg);
      min-height: 100vh;
      display: flex;
      align-items: flex-start;
      justify-content: center;
      padding: 40px 16px;
      color: var(--text-1);
    }

    .wrapper { width: 100%; max-width: 780px; }

    /* ── Top bar ── */
    .topbar {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 20px;
    }
    .topbar-brand {
      font-size: 13px;
      font-weight: 500;
      color: var(--text-3);
      letter-spacing: 0.04em;
      text-transform: uppercase;
    }
    .topbar-brand span { color: var(--text-1); }
    .badge-pending {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      font-size: 12px;
      font-weight: 500;
      background: var(--amber-bg);
      color: var(--amber-tx);
      border: 1px solid var(--amber-bd);
      padding: 5px 12px;
      border-radius: 20px;
    }
    .badge-pending::before {
      content: '';
      width: 7px; height: 7px;
      border-radius: 50%;
      background: var(--amber-bd);
      flex-shrink: 0;
    }

    /* ── Card ── */
    .card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: var(--radius-lg);
      overflow: hidden;
      box-shadow: 0 2px 12px rgba(0,0,0,0.05);
    }

    /* ── Header ── */
    .card-header {
      padding: 24px 28px 20px;
      border-bottom: 1px solid var(--border);
    }
    .subject {
      font-size: 16px;
      font-weight: 500;
      line-height: 1.45;
      margin-bottom: 16px;
      color: var(--text-1);
    }
    .meta-row { display: flex; flex-wrap: wrap; gap: 4px 0; }
    .meta-item {
      display: flex;
      align-items: baseline;
      gap: 6px;
      font-size: 13px;
      width: 100%;
    }
    .meta-label {
      color: var(--text-3);
      font-size: 12px;
      font-weight: 500;
      min-width: 36px;
      letter-spacing: 0.03em;
    }
    .meta-value { color: var(--text-2); }
    .timestamp {
      font-size: 12px;
      color: var(--text-3);
      font-family: 'DM Mono', monospace;
      margin-top: 14px;
    }

    /* ── Body ── */
    .card-body { padding: 28px; }

    .section-label {
      font-size: 11px;
      font-weight: 600;
      color: var(--text-3);
      letter-spacing: 0.08em;
      text-transform: uppercase;
      margin-bottom: 12px;
    }

    .content-block {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: var(--radius-md);
      padding: 22px 24px;
      margin-bottom: 28px;
    }
    .content-block p {
      font-size: 15px;
      line-height: 1.8;
      color: var(--text-1);
      white-space: pre-wrap;
    }

    /* ── Action buttons (links styled as buttons) ── */
    .actions-label {
      font-size: 11px;
      font-weight: 600;
      color: var(--text-3);
      letter-spacing: 0.08em;
      text-transform: uppercase;
      margin-bottom: 12px;
    }

    .btn-group {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 10px;
    }

    .btn {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      padding: 13px 16px;
      border-radius: var(--radius-md);
      border: 1px solid;
      font-family: 'DM Sans', sans-serif;
      font-size: 14px;
      font-weight: 500;
      cursor: pointer;
      text-decoration: none;
      transition: transform 0.12s, opacity 0.12s;
    }
    .btn:hover { opacity: 0.82; transform: translateY(-1px); }
    .btn:active { transform: scale(0.97); }

    .btn-approve {
      background: var(--green-bg);
      border-color: var(--green-bd);
      color: var(--green-tx);
    }
    .btn-reject {
      background: var(--red-bg);
      border-color: var(--red-bd);
      color: var(--red-tx);
    }
    .btn-edit {
      background: var(--blue-bg);
      border-color: var(--blue-bd);
      color: var(--blue-tx);
    }

    /* ── Footer ── */
    .card-footer {
      padding: 14px 28px;
      border-top: 1px solid var(--border);
      display: flex;
      align-items: center;
      justify-content: space-between;
      background: var(--surface2);
    }
    .footer-note {
      font-size: 12px;
      color: var(--text-3);
    }
    .footer-note a {
      color: var(--text-3);
      text-decoration: underline;
      text-underline-offset: 2px;
    }
    .dfid-badge {
      font-size: 12px;
      font-weight: 500;
      font-family: 'DM Mono', monospace;
      color: var(--text-3);
    }

    @media (max-width: 520px) {
      .btn-group { grid-template-columns: 1fr; }
      .card-header, .card-body { padding: 20px 18px; }
      .card-footer { flex-direction: column; gap: 6px; text-align: center; }
    }
  </style>
</head>
<body>
<div class="wrapper">

  <div class="topbar">
    <div class="topbar-brand">Lockated · <span>Marketing Review</span></div>
    <div class="badge-pending">Pending Review</div>
  </div>

  <div class="card">

    <!-- Header -->
    <div class="card-header">
      <p class="subject">
        DFID-{{$json.Draft_ID}} | LinkedIn Draft Ready for Review — {{$json.Topic}}
      </p>
      <div class="meta-row">
        <div class="meta-item">
          <span class="meta-label">From</span>
          <span class="meta-value">marketing@lockated.com</span>
        </div>
        <div class="meta-item">
          <span class="meta-label">To</span>
          <span class="meta-value">suyash.jagdale@lockated.com</span>
        </div>
        <div class="meta-item">
          <span class="meta-label">Cc</span>
          <span class="meta-value">manav.gandhi@lockated.com</span>
        </div>
      </div>
      <div class="timestamp">{{$now.toFormat('MMMM d, yyyy')}} · {{$now.toFormat('h:mm a')}}</div>
    </div>

    <!-- Body -->
    <div class="card-body">

      <div class="section-label">LinkedIn post draft</div>

      <div class="content-block">
        <p>{{$json.Post_Content}}</p>
      </div>

      <div class="actions-label">Review action</div>

      <div class="btn-group">

        <!-- APPROVE -->
        <a href="https://automation.lockated.com/webhook-test/linkedin-review?action=Approved&id={{$json.Draft_ID}}&content={{encodeURIComponent($json.Post_Content)}}&reply_to={{encodeURIComponent('suyash.jagdale@lockated.com')}}&cc={{encodeURIComponent('manav.gandhi@lockated.com')}}"
           class="btn btn-approve">
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path d="M3 8L6.5 11.5L13 5" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/>
          </svg>
          Approve
        </a>

        <!-- REJECT -->
        <a href="https://automation.lockated.com/webhook-test/linkedin-review?action=Rejected&id={{$json.Draft_ID}}&content={{encodeURIComponent($json.Post_Content)}}&reply_to={{encodeURIComponent('suyash.jagdale@lockated.com')}}&cc={{encodeURIComponent('manav.gandhi@lockated.com')}}"
           class="btn btn-reject">
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path d="M4.5 4.5L11.5 11.5M11.5 4.5L4.5 11.5" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>
          </svg>
          Reject
        </a>

        <!-- EDIT -->
        <a href="https://automation.lockated.com/webhook-test/linkedin-review-edit?action=Edit&id={{$json.Draft_ID}}&content={{encodeURIComponent($json.Post_Content)}}&reply_to={{encodeURIComponent('suyash.jagdale@lockated.com')}}&cc={{encodeURIComponent('manav.gandhi@lockated.com')}}"
           class="btn btn-edit">
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path d="M11 2.5L13.5 5L6 12.5H3.5V10L11 2.5Z" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
          </svg>
          Edit
        </a>

      </div>

    </div>

    <!-- Footer -->
    <div class="card-footer">
      <span class="footer-note">Sent automatically via <a href="#">n8n</a> automation</span>
      <span class="dfid-badge">DFID-{{$json.Draft_ID}}</span>
    </div>

  </div>
</div>
</body>
</html>
